import React, { useState, useEffect } from 'react';
import api from '../lib/api';

const Dashboard = () => {
  const [stats, setStats] = useState({
    totalDevices: 0,
    activeDevices: 0,
    inactiveDevices: 0,
    totalBackups: 0,
    recentAlerts: 0
  });
  const [devices, setDevices] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      const response = await api.get('/devices/');
      const deviceList = response.data.results || response.data || [];
      setDevices(deviceList);

      const active = deviceList.filter(d => d.status === 'active' || d.is_active).length;
      const inactive = deviceList.filter(d => d.status !== 'active' && !d.is_active).length;

      setStats({
        totalDevices: deviceList.length,
        activeDevices: active,
        inactiveDevices: inactive,
        totalBackups: 0,
        recentAlerts: 0
      });
    } catch (error) {
      console.log('Error loading dashboard data:', error);
    } finally {
      setLoading(false);
    }
  };

  const statCards = [
    { label: 'Total de Dispositivos', value: stats.totalDevices, icon: '🖥️', color: 'bg-blue-600' },
    { label: 'Dispositivos Ativos', value: stats.activeDevices, icon: '✅', color: 'bg-green-600' },
    { label: 'Dispositivos Inativos', value: stats.inactiveDevices, icon: '⚠️', color: 'bg-yellow-600' },
    { label: 'Backups', value: stats.totalBackups, icon: '💾', color: 'bg-purple-600' },
  ];

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="text-gray-400">Carregando...</div>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((stat, index) => (
          <div key={index} className="bg-gray-800 rounded-lg p-6">
            <div className="flex items-center justify-between">
              <div>
                <p className="text-gray-400 text-sm">{stat.label}</p>
                <p className="text-3xl font-bold text-white mt-1">{stat.value}</p>
              </div>
              <div className={`w-12 h-12 ${stat.color} rounded-lg flex items-center justify-center`}>
                <span className="text-2xl">{stat.icon}</span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Recent Devices */}
      <div className="bg-gray-800 rounded-lg p-6">
        <h2 className="text-lg font-semibold text-white mb-4">Dispositivos Recentes</h2>
        {devices.length === 0 ? (
          <p className="text-gray-400">Nenhum dispositivo cadastrado</p>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="text-left text-gray-400 text-sm">
                  <th className="pb-3">Nome</th>
                  <th className="pb-3">IP</th>
                  <th className="pb-3">Tipo</th>
                  <th className="pb-3">Status</th>
                </tr>
              </thead>
              <tbody className="text-white">
                {devices.slice(0, 5).map((device, index) => (
                  <tr key={device.id || index} className="border-t border-gray-700">
                    <td className="py-3">{device.name || device.hostname || '-'}</td>
                    <td className="py-3">{device.ip || device.ip_address || '-'}</td>
                    <td className="py-3">{device.device_type || device.type || '-'}</td>
                    <td className="py-3">
                      <span className={`px-2 py-1 rounded text-xs ${
                        (device.status === 'active' || device.is_active) 
                          ? 'bg-green-600/20 text-green-400' 
                          : 'bg-red-600/20 text-red-400'
                      }`}>
                        {(device.status === 'active' || device.is_active) ? 'Ativo' : 'Inativo'}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Quick Actions */}
      <div className="bg-gray-800 rounded-lg p-6">
        <h2 className="text-lg font-semibold text-white mb-4">Ações Rápidas</h2>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <button className="p-4 bg-gray-700 hover:bg-gray-600 rounded-lg text-center transition">
            <span className="text-2xl block mb-2">➕</span>
            <span className="text-white text-sm">Novo Dispositivo</span>
          </button>
          <button className="p-4 bg-gray-700 hover:bg-gray-600 rounded-lg text-center transition">
            <span className="text-2xl block mb-2">🔄</span>
            <span className="text-white text-sm">Sincronizar</span>
          </button>
          <button className="p-4 bg-gray-700 hover:bg-gray-600 rounded-lg text-center transition">
            <span className="text-2xl block mb-2">💾</span>
            <span className="text-white text-sm">Backup</span>
          </button>
          <button className="p-4 bg-gray-700 hover:bg-gray-600 rounded-lg text-center transition">
            <span className="text-2xl block mb-2">📊</span>
            <span className="text-white text-sm">Relatórios</span>
          </button>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;
